const DEFAULTS = {
  leadName: "",
  leadEmail: "",
  representative: "",
  budget: "budget",
  destinations: [],
  guestCountRange: "10-20",
  adultsOnly: false,
  flightsNeeded: false,
};

const ALLOWED_BUDGETS = new Set(["budget", "economy", "elevated", "luxury"]);
const ALLOWED_RANGES = new Set(["< 10", "10-20", "20-50", "50-100", "100+"]);

function getModelText(input) {
  return (
    input?.output?.[0]?.content?.[0]?.text ||
    input?.data?.output?.[0]?.content?.[0]?.text ||
    ""
  );
}

function parseJsonStrict(text) {
  try {
    return JSON.parse(text);
  } catch (_) {
    const match = String(text).match(/\{[\s\S]*\}/);
    if (!match) throw new Error("Model did not return valid JSON.");
    return JSON.parse(match[0]);
  }
}

function normalizeGuestRange(v) {
  if (typeof v !== "string") return DEFAULTS.guestCountRange;

  let s = v.trim();

  if (s === "<10") s = "< 10";
  if (s === "20–50") s = "20-50";
  if (/20\s*to\s*50/i.test(s)) s = "20-50";
  if (/10\s*to\s*20/i.test(s)) s = "10-20";
  if (/50\s*to\s*100/i.test(s)) s = "50-100";

  return ALLOWED_RANGES.has(s) ? s : DEFAULTS.guestCountRange;
}

function normalizeBudget(v) {
  if (typeof v !== "string") return DEFAULTS.budget;
  const s = v.trim().toLowerCase();
  return ALLOWED_BUDGETS.has(s) ? s : DEFAULTS.budget;
}

function normalizeDestinations(v) {
  if (!Array.isArray(v)) return [];
  return v
    .map((d) => (typeof d === "string" ? d.trim() : ""))
    .filter(Boolean);
}

function toBool(v) {
  if (typeof v === "boolean") return v;
  if (typeof v === "string") {
    const s = v.trim().toLowerCase();
    if (s === "true") return true;
    if (s === "false") return false;
  }
  return Boolean(v);
}

function toTrimmedString(v) {
  return typeof v === "string" ? v.trim() : "";
}


const text = getModelText($json);

if (!text) {
  throw new Error("No model output text found at output[0].content[0].text");
}

const raw = parseJsonStrict(text);

if (!raw || typeof raw !== "object" || Array.isArray(raw)) {
  throw new Error("Parsed model output is not an object");
}

const data = {
  leadName: toTrimmedString(raw.leadName),
  leadEmail: toTrimmedString(raw.leadEmail),
  representative: toTrimmedString(raw.representative),

  budget: normalizeBudget(raw.budget),
  guestCountRange: normalizeGuestRange(raw.guestCountRange),
  destinations: normalizeDestinations(raw.destinations),

  adultsOnly: toBool(raw.adultsOnly),
  flightsNeeded: toBool(raw.flightsNeeded),
};

return [{ json: { ok: true, data } }];
